import java.util.Queue

fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val adj = Array(n) { mutableListOf<Pair<Int, Long>>() }
    val inDegree = LongArray(n) { 0L }

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val cost = edge[2]
        adj[u].add(Pair(v, cost))
        inDegree[v] += 1
    }

    val queue = LinkedList<Int>()
    for (i in 0 until n) {
        if (inDegree[i] == 0L) {
            queue.add(i)
        }
    }

    val topologicalOrder = mutableListOf<Int>()
    while (queue.isNotEmpty()) {
        val u = queue.pollFirst()
        topologicalOrder.add(u)
        for (pair in adj[u]) {
            val v = pair.first
            inDegree[v] -= 1
            if (inDegree[v] == 0L) {
                queue.add(v)
            }
        }
    }

    val maxMin = LongArray(n) { Long.MIN_VALUE }
    val totalCost = LongArray(n) { 0L }
    maxMin[0] = Long.MAX_VALUE
    totalCost[0] = 0L

    for (u in topologicalOrder) {
        for (pair in adj[u]) {
            val v = pair.first
            val cost = pair.second
            if (!online[u] || !online[v]) {
                continue
            }
            if (maxMin[u] == Long.MIN_VALUE) {
                continue
            }
            val newMin = min(maxMin[u], cost)
            val newTotal = totalCost[u] + cost
            if (newTotal > k) {
                continue
            }
            if (newMin > maxMin[v]) {
                maxMin[v] = newMin
                totalCost[v] = newTotal
            } else if (newMin == maxMin[v] && newTotal < totalCost[v]) {
                totalCost[v] = newTotal
            }
        }
    }

    return if (maxMin[n - 1] == Long.MIN_VALUE) -1 else maxMin[n - 1]
}
