fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val adj = Array(n) { mutableListOf<Pair<Int, Long>>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val cost = edge[2]
        adj[u].add(Pair(v, cost))
    }

    val bestMinEdge = LongArray(n)
    for (i in 0 until n) {
        bestMinEdge[i] = -Long.MAX_VALUE
    }
    bestMinEdge[0] = Long.MAX_VALUE

    data class HeapEntry(val currentMin: Long, val totalCost: Long, val node: Int)

    val pq = PriorityQueue<HeapEntry> { a, b -> 
        (a.currentMin * -1).compareTo(b.currentMin * -1) 
    }

    pq.add(HeapEntry(Long.MAX_VALUE, 0L, 0))

    var result = -1L

    while (pq.isNotEmpty()) {
        val entry = pq.poll()
        val currentMin = entry.currentMin
        val totalCost = entry.totalCost
        val node = entry.node

        if (node == n - 1) {
            result = currentMin
            break
        }

        if (currentMin < bestMinEdge[node]) {
            continue
        }

        for (edge in adj[node]) {
            val v = edge.first
            if (!online[v]) continue
            val cost = edge.second
            val newTotal = totalCost + cost
            if (newTotal > k) continue
            val newMin = min(currentMin, cost)
            if (newMin > bestMinEdge[v]) {
                bestMinEdge[v] = newMin
                pq.add(HeapEntry(newMin, newTotal, v))
            }
        }
    }

    return result
}
